query:
ALTER TABLE products ADD COLUMN isPlatform BOOLEAN DEFAULT FALSE AFTER competitorFlag;
ALTER TABLE products ADD COLUMN updatedAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP;
UPDATE products SET isPlatform = TRUE WHERE organizationId IS NULL;
SELECT id, name, company, category, organizationId, isPlatform FROM products LIMIT 20;

